// supplier-products.service.ts
import { Injectable, inject } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';
import { SupplierAuthService } from './supplier-auth.service';
import { BehaviorSubject } from 'rxjs';

export interface Unit {
  id: string;
  name: string;
  symbol: string;
  type: string;
}

export interface IngredientReference {
  id: string;
  name: string;
}

export interface SupplierProduct {
  id: string;
  supplier_id: string;
  product_name: string;
  description?: string;
  unit_price: number;
  package_quantity: number;
  unit_id?: string;
  ingredient_id?: string;
  is_available: boolean;
  created_at: string;
  units?: Unit;
  ingredients?: IngredientReference;
}

@Injectable({
  providedIn: 'root'
})
export class SupplierProductsService {
  private supabaseService = inject(SupabaseService);
  private supplierAuthService = inject(SupplierAuthService);

  private productsSubject = new BehaviorSubject<SupplierProduct[]>([]);
  public products$ = this.productsSubject.asObservable();

  async loadSupplierProducts(): Promise<void> {
    try {
      const supplier = this.supplierAuthService.getSupplierProfile();
      if (!supplier) {
        console.error('No supplier profile found');
        return;
      }

      const { data: products, error } = await this.supabaseService.getSupabaseClient()
        .from('supplier_products')
        .select(`
          *,
          units (name, symbol),
          ingredients (name)
        `)
        .eq('supplier_id', supplier.id)
        .order('product_name');

      if (error) {
        console.error('Error loading supplier products:', error);
        return;
      }

      this.productsSubject.next(products || []);
    } catch (error) {
      console.error('Error in loadSupplierProducts:', error);
    }
  }

  async createProduct(product: Omit<SupplierProduct, 'id' | 'created_at' | 'supplier_id'>): Promise<SupplierProduct | null> {
    try {
      const supplier = this.supplierAuthService.getSupplierProfile();
      if (!supplier) {
        console.error('No supplier profile found');
        return null;
      }

      const productWithSupplier = {
        ...product,
        supplier_id: supplier.id
      };

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('supplier_products')
        .insert(productWithSupplier)
        .select()
        .single();

      if (error) throw error;
      
      await this.loadSupplierProducts();
      return data;
    } catch (error) {
      console.error('Error creating supplier product:', error);
      return null;
    }
  }

  async updateProduct(id: string, updates: Partial<SupplierProduct>): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('supplier_products')
        .update(updates)
        .eq('id', id);

      if (error) throw error;
      
      await this.loadSupplierProducts();
      return true;
    } catch (error) {
      console.error('Error updating supplier product:', error);
      return false;
    }
  }

  async deleteProduct(id: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('supplier_products')
        .delete()
        .eq('id', id);

      if (error) throw error;
      
      await this.loadSupplierProducts();
      return true;
    } catch (error) {
      console.error('Error deleting supplier product:', error);
      return false;
    }
  }

  getProducts(): SupplierProduct[] {
    return this.productsSubject.value;
  }

  getAvailableProducts(): SupplierProduct[] {
    return this.productsSubject.value.filter(product => product.is_available);
  }

  getProductById(id: string): SupplierProduct | undefined {
    return this.productsSubject.value.find(product => product.id === id);
  }
}